new_method = '\r\n    def _show_audit_card(self, event):\r\n        print("DEBUG: _show_audit_card called")\r\n        selection = self.audit_tree.selection()\r\n        if not selection:\r\n            print("DEBUG: no selection")\r\n            return\r\n        item = selection[0]\r\n        vals = self.audit_tree.item(item, "values")\r\n        cols = list(self.audit_tree["columns"])\r\n        print(f"DEBUG: cols length={len(cols)}, vals length={len(vals)}")\r\n\r\n        # 补齐或截断 vals 使其与 cols 长度一致\r\n        vals = list(vals)\r\n        if len(vals) < len(cols):\r\n            vals = vals + [\'\'] * (len(cols) - len(vals))\r\n        else:\r\n            vals = vals[:len(cols)]\r\n        data = dict(zip(cols, vals))\r\n\r\n        # 销毁旧窗口\r\n        if hasattr(self, "_card_win") and self._card_win and self._card_win.winfo_exists():\r\n            self._card_win.destroy()\r\n\r\n        self._card_win = tk.Toplevel(self.root)\r\n        self._card_win.title("审核卡片")\r\n        self._card_win.geometry("520x580")\r\n        self._card_win.minsize(450, 500)\r\n        self._card_win.transient(self.root)\r\n        self._card_win.attributes("-topmost", True)\r\n\r\n        self.root.update_idletasks()\r\n        rx = self.root.winfo_rootx() + self.root.winfo_width() + 5\r\n        ry = self.root.winfo_rooty() + 100\r\n        self._card_win.geometry(f"+{rx}+{ry}")\r\n\r\n        card_bg = "#fefefe"\r\n        self._card_win.configure(bg=card_bg)\r\n\r\n        tk.Label(self._card_win, text="📋 审核卡片", font=("Microsoft YaHei", 12, "bold"),\r\n                 bg=card_bg).pack(pady=(12, 6))\r\n\r\n        text = tk.Text(self._card_win, font=("Microsoft YaHei", 10), bg=card_bg,\r\n                       relief="flat", wrap="word", height=20)\r\n        text.pack(fill="both", expand=True, padx=12, pady=6)\r\n\r\n        # 构建显示内容\r\n        lines = []\r\n        for c in cols:\r\n            if c == "idx":\r\n                continue\r\n            val = str(data.get(c, ""))\r\n            if val:\r\n                lines.append(f"{c}：{val}")\r\n        if not lines:\r\n            lines = ["（无数据显示）", f"行ID：{item}"]\r\n        info = "\\n".join(lines)\r\n\r\n        # 成本换算器（简化版，确保不会崩溃）\r\n        try:\r\n            dev_amount_raw = data.get("deviation_amount", "0")\r\n            if dev_amount_raw and str(dev_amount_raw).strip() not in ("0", "-", ""):\r\n                dev_amount_clean = str(dev_amount_raw).replace(",", "")\r\n                dev_amount_val = float(dev_amount_clean) if dev_amount_clean else 0\r\n                if abs(dev_amount_val) > 0.001:\r\n                    excel_row = data.get("excel_row")\r\n                    unit_price = 0.0\r\n                    unit_name = ""\r\n                    if self.audit_data is not None and excel_row:\r\n                        try:\r\n                            row_int = int(float(excel_row))\r\n                            if "excel_row" in self.audit_data.columns:\r\n                                mask = self.audit_data["excel_row"].astype(str).astype(float).astype(int) == row_int\r\n                                if mask.any():\r\n                                    row = self.audit_data[mask].iloc[0]\r\n                                    unit_price = row.get(\'_unit_price\', 0)\r\n                                    if unit_price <= 0:\r\n                                        for price_col in ["单价", "_单价", "unit_price"]:\r\n                                            if price_col in row.index:\r\n                                                unit_price = float(row[price_col] or 0)\r\n                                                break\r\n                                    for unit_col in ["组件单位", "单位"]:\r\n                                        if unit_col in row.index:\r\n                                            unit_name = str(row[unit_col] or "")\r\n                                            break\r\n                        except:\r\n                            pass\r\n                    if unit_price > 0:\r\n                        est_qty = abs(dev_amount_val) / unit_price\r\n                        ud = unit_name if unit_name else "单位"\r\n                        sign_icon = "↑" if dev_amount_val > 0 else "↓"\r\n                        info += f"\\n💰 偏差金额：¥{dev_amount_val:,.2f} {sign_icon} ≈ {est_qty:.1f} {ud}（单价 ¥{unit_price:.2f}/{ud}）"\r\n                    else:\r\n                        info += f"\\n⚠️ 无法获取单价，请确保原始数据包含金额和数量列"\r\n        except Exception as e:\r\n            info += f"\\n⚠️ 成本换算失败：{e}"\r\n\r\n        text.insert("1.0", info)\r\n        text.configure(state="disabled")\r\n\r\n        # 常用备注按钮\r\n        btn_fr = tk.Frame(self._card_win, bg=card_bg)\r\n        btn_fr.pack(pady=(0, 10))\r\n\r\n        preset_remarks = ["系统无定额", "替代料", "已核实", "工艺调整", "其他"]\r\n        sorted_remarks, freq = self._get_sorted_remarks(preset_remarks)\r\n\r\n        def fill_remark(tag):\r\n            self.audit_tree.set(item, "remark", tag)\r\n            self.audit_tree.set(item, "status", "已备注")\r\n            excel_row_val = data.get("excel_row")\r\n            if self.audit_data is not None and excel_row_val:\r\n                try:\r\n                    row_int = int(float(excel_row_val))\r\n                    if "excel_row" in self.audit_data.columns:\r\n                        mask = self.audit_data["excel_row"].astype(str).astype(float).astype(int) == row_int\r\n                        if mask.any():\r\n                            self.audit_data.loc[mask, "备注原因"] = tag\r\n                except:\r\n                    pass\r\n            self._record_remark_freq(tag)\r\n            self._card_win.destroy()\r\n\r\n        for i, remark in enumerate(sorted_remarks):\r\n            count = freq.get(remark, 0)\r\n            if i < 3 and count > 0:\r\n                btn_font = ("Microsoft YaHei", 10, "bold")\r\n                btn_bg = "#bbdefb"\r\n            else:\r\n                btn_font = ("Microsoft YaHei", 9)\r\n                btn_bg = "#e3f2fd" if "无定额" in remark else "#fff9c4" if "替代" in remark else "#f5f5f5"\r\n            tk.Button(btn_fr, text=f"{remark}({count})" if count > 0 else remark,\r\n                      command=lambda r=remark: fill_remark(r), bg=btn_bg,\r\n                      font=btn_font, relief="flat", width=12).pack(side="left", padx=3)\r\n\r\n        print("DEBUG: _show_audit_card finished")\r\n'

# 找到方法开始位置
start_pat = '    def _show_audit_card(self, event):\r\n'
start_idx = content.find(start_pat)
if start_idx == -1:
    print("ERROR: start pattern not found")
    exit(1)

# 找下一个同级 def
rest = content[start_idx + len(start_pat):]
next_def = re.search(r'\r\n    def ', rest)
if not next_def:
    print("ERROR: end not found")
    exit(1)

end_idx = start_idx + len(start_pat) + next_def.start()
old_text = content[start_idx:end_idx]

print(f"Old method length: {len(old_text)}")
print(f"New method length: {len(new_method)}")

new_content = content[:start_idx] + new_method + content[end_idx:]
with open(filepath, 'w', encoding='utf-8-sig', newline='') as f:
    f.write(new_content)

print("DONE: _show_audit_card replaced successfully")
